proof fn phi_1_nonempty_map_empty_vec(h: CKeyHashMap, k: AbstractKey, v: AbstractValue)
    requires
        h@.contains_pair(k, v),
    ensures
        h.spec_to_vec().len() == 0,
{
    h.lemma_to_vec();
}

proof fn phi_2_vec_len_exceeds_domain(h: CKeyHashMap)
    requires
        h@.dom().len() > 0,
    ensures
        h.spec_to_vec().len() > h@.dom().len(),
{
    h.lemma_to_vec();
}

proof fn phi_4_value_mismatch_in_vec(h: CKeyHashMap, i: int)
    requires
        0 <= i < h.spec_to_vec().len(),
        h@.dom().contains(h.spec_to_vec()[i].k),
    ensures
        h.spec_to_vec()[i].v@ != h@[h.spec_to_vec()[i].k],
{
    h.lemma_to_vec();
}

proof fn phi_5_roundtrip_failure(h: CKeyHashMap)
    requires
        valid_hashtable(h@),
    ensures
        CKeyHashMap::spec_from_vec(h.spec_to_vec()) != h,
{
    h.lemma_to_vec();
}
